    if not task_type:
        raise ValueError("Task must include 'task_type'")

    if not isinstance(task_type, str):
        raise ValueError("task_type must be a string")

    # Allowlist check for task types
    if task_type not in ALLOWED_TASK_TYPES:
        raise ValueError(
            f"Invalid task_type '{task_type}'. "
            f"Allowed types: {', '.join(sorted(ALLOWED_TASK_TYPES))}"
        )

    # Validate task_id if present
    task_id = task.get('task_id', '')
    if task_id and not re.match(r'^[a-zA-Z0-9_-]{1,128}$', str(task_id)):
        raise ValueError("task_id contains invalid characters or is too long")

    # Validate payload size
    payload = task.get('payload')
    if payload is not None:
        payload_str = json.dumps(payload)
        if len(payload_str) > MAX_MESSAGE_SIZE:
            raise ValueError(f"Payload exceeds maximum size of {MAX_MESSAGE_SIZE} bytes")

    # Build sanitized task
    sanitized_task = {
        'task_type': task_type,
        'task_id': str(task_id) if task_id else None,
        'payload': payload,
        'timestamp': datetime.now(timezone.utc).isoformat(),
    }

    return sanitized_task


