        # Build message properties
        properties = pika.BasicProperties(
            delivery_mode=pika.DeliveryMode.Persistent,  # Persist messages to disk
            content_type='application/json',
            content_encoding='utf-8',
            priority=priority,
            headers={
                'x-signature': signature,
                'x-publisher': 'task-publisher',
                'x-timestamp': sanitized_task['timestamp'],
            },
            expiration='86400000',  # 24 hour TTL
        )

