class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ with authentication and verification."""

    def __init__(self, prefetch_count: int = 1):
        self._connection: Optional[pika.BlockingConnection] = None
        self._channel = None
        self._prefetch_count = max(1, min(100, prefetch_count))
        self._task_handlers: Dict[str, callable] = {}

    def register_handler(self, task_type: str, handler: callable):
        """Register a handler function for a specific task type."""
        if task_type not in ALLOWED_TASK_TYPES:
            raise ValueError(f"Cannot register handler for disallowed task type: {task_type}")
        self._task_handlers[task_type] = handler
        logger.info("Registered handler for task type: %s", task_type)

    def connect(self):
        """Establish authenticated connection to RabbitMQ."""
        parameters = _get_connection_parameters()
        self._connection = pika.BlockingConnection(parameters)
        self._channel = self._connection.channel()

        # Declare the same durable queue
        self._channel.queue_declare(
            queue=QUEUE_NAME,
            durable=True,
            arguments={
                'x-max-length': 100000,
                'x-message-ttl': 86400000,
                'x-max-priority': 10,
            }
        )

        # Fair dispatch: don't give more than prefetch_count messages at a time
        self._channel.basic_qos(prefetch_count=self._prefetch_count)
        logger.info("Consumer connected to RabbitMQ with prefetch_count=%d", self._prefetch_count)

    def _on_message(self, channel, method, properties, body):
        """
        Callback for processing received messages.
        Validates signature, deserializes, and dispatches to appropriate handler.
        """
        try:
            # Check message size
            if len(body) > MAX_MESSAGE_SIZE:
                logger.warning("Received oversized message (%d bytes), rejecting", len(body))
                channel.basic_reject(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Verify message signature
            headers = properties.headers or {}
            signature = headers.get('x-signature', '')

            if MESSAGE_SIGNING_SECRET and not signature:
                logger.warning("Received unsigned message, rejecting")
                channel.basic_reject(delivery_tag=method.delivery_tag, requeue=False)
                return

            if not _verify_message_signature(body, signature):
                logger.warning("Message signature verification failed, rejecting")
                channel.basic_reject(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Deserialize message
            try:
                task = json.loads(body.decode('utf-8'))
            except (json.JSONDecodeError, UnicodeDecodeError) as e:
                logger.error("Failed to deserialize message: %s", str(e))
                channel.basic_reject(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Validate the task structure
            try:
                validated_task = validate_task_message(task)
            except ValueError as e:
                logger.error("Task validation failed: %s", str(e))
                channel.basic_reject(delivery_tag=method.delivery_tag, requeue=False)
                return

            task_type = validated_task['task_type']
            task_id = validated_task.get('task_id', 'N/A')

            logger.info("Processing task: type=%s, id=%s", task_type, task_id)

            # Dispatch to registered handler
            handler = self._task_handlers.get(task_type)
            if handler is None:
                logger.warning("No handler registered for task type: %s", task_type)
                # Requeue so another consumer with the right handler can process it
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
                return

            # Execute the handler
            handler(validated_task)

            # Acknowledge successful processing
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info("Task completed: type=%s, id=%s", task_type, task_id)

        except Exception as e:
            logger.error("Error processing message: %s", str(e))
            # Negative acknowledge and requeue for retry
            try:
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            except Exception:
                logger.error("Failed to nack message")

    def start_consuming(self):
        """Start consuming messages from the queue."""
        if not self._channel or self._channel.is_closed:
            raise ConnectionError("Not connected to RabbitMQ. Call connect() first.")

        self._channel.basic_consume(
            queue=QUEUE_NAME,
            on_message_callback=self._on_message,
            auto_ack=False,  # Manual acknowledgment for reliability
        )

        logger.info("Consumer started, waiting for tasks...")
        try:
            self._channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self._channel.stop_consuming()

    def close(self):
        """Close the connection gracefully."""
        if self._connection and not self._connection.is_closed:
            self._connection.close()
            logger.info("Consumer connection closed")


